   331	// GetAuthPluginForConnection gets the authentication plugin used in connection establishment.
   332	func (p *UserPrivileges) GetAuthPluginForConnection(user, host string) (string, error) {
   333		if SkipWithGrant {
   334			return mysql.AuthNativePassword, nil
   335		}
   336	
   337		mysqlPriv := p.Handle.Get()
   338		record := mysqlPriv.connectionVerification(user, host)
   339		if record == nil {
   340			return "", errors.New("Failed to get user record")
   341		}
   342		if authPlugin, ok := p.authPlugins[record.AuthPlugin]; ok {
   343			return authPlugin.Name, nil
   344		}
   345		switch record.AuthPlugin {
   346		case mysql.AuthTiDBAuthToken, mysql.AuthLDAPSASL, mysql.AuthLDAPSimple:
   347			return record.AuthPlugin, nil
   348		}
   349	
   350		// zero-length auth string means no password for native and caching_sha2 auth.
   351		// but for auth_socket it means there should be a 1-to-1 mapping between the TiDB user
   352		// and the OS user.
   353		if record.AuthenticationString == "" && record.AuthPlugin != mysql.AuthSocket {
   354			return "", nil
   355		}
   356		if p.isValidHash(record) {
   357			return record.AuthPlugin, nil
   358		}
   359		return "", errors.New("Failed to get plugin for user")
   360	}
